import crypto from 'crypto'
import { hashPassword } from './crypto'
import { renderResetEmail } from './resetEmail'

function digest(token: string): string {
  return crypto.createHash('sha256').update(token).digest('hex')
}

export async function requestPasswordResetHandler(req, res, deps) {
  const { email } = req.body
  const user = await deps.users.findByEmail(email)
  if (!user) return res.status(202).json({ ok: true })

  const token = crypto.randomBytes(32).toString('hex')
  const tokenHash = digest(token)
  const expiresAt = new Date(Date.now() + deps.config.auth.resetTokenTtlMs)

  await deps.resetTokens.create({ userId: user.id, tokenHash, expiresAt })

  const url = `${deps.config.webBaseUrl}/reset-password?token=${token}`
  await deps.mailer.send({ to: email, subject: 'Reset your password', html: renderResetEmail(url) })

  return res.status(202).json({ ok: true })
}

export async function confirmPasswordResetHandler(req, res, deps) {
  const { token, password } = req.body
  const tokenHash = digest(token)
  const record = await deps.resetTokens.findValidByHash(tokenHash)
  if (!record) return res.status(400).json({ error: 'invalid_or_expired_token' })

  const passwordHash = await hashPassword(password)
  await deps.users.updatePassword(record.userId, passwordHash)
  await deps.resetTokens.consume(record.id)

  return res.status(200).json({ ok: true })
}

