import { describe, it, expect, vi } from 'vitest'
import { requestPasswordResetHandler, confirmPasswordResetHandler } from '../../src/auth/passwordReset'

describe('password reset flow', () => {
  it('returns 202 for unknown email', async () => {
    const deps = { users: { findByEmail: vi.fn().mockResolvedValue(null) } } as any
    const req = { body: { email: 'missing@example.com' } } as any
    const res = { status: vi.fn().mockReturnThis(), json: vi.fn() } as any
    await requestPasswordResetHandler(req, res, deps)
    expect(res.status).toHaveBeenCalledWith(202)
  })

  it('creates token and sends reset email', async () => {
    const deps = {
      config: { auth: { resetTokenTtlMs: 1800000 }, webBaseUrl: 'http://localhost:3000' },
      users: { findByEmail: vi.fn().mockResolvedValue({ id: 'u1', email: 'a@b.com' }) },
      resetTokens: { create: vi.fn() },
      mailer: { send: vi.fn() }
    } as any
    const req = { body: { email: 'a@b.com' } } as any
    const res = { status: vi.fn().mockReturnThis(), json: vi.fn() } as any
    await requestPasswordResetHandler(req, res, deps)
    expect(deps.resetTokens.create).toHaveBeenCalledOnce()
    expect(deps.mailer.send).toHaveBeenCalledOnce()
  })

  it('rejects invalid token on confirm', async () => {
    const deps = { resetTokens: { findValidByHash: vi.fn().mockResolvedValue(null) } } as any
    const req = { body: { token: 'bad', password: 'next-pass' } } as any
    const res = { status: vi.fn().mockReturnThis(), json: vi.fn() } as any
    await confirmPasswordResetHandler(req, res, deps)
    expect(res.status).toHaveBeenCalledWith(400)
  })

  it('updates password and consumes token', async () => {
    const deps = {
      resetTokens: {
        findValidByHash: vi.fn().mockResolvedValue({ id: 'r1', userId: 'u1' }),
        consume: vi.fn()
      },
      users: { updatePassword: vi.fn() }
    } as any
    const req = { body: { token: 'ok', password: 'new-password-123' } } as any
    const res = { status: vi.fn().mockReturnThis(), json: vi.fn() } as any
    await confirmPasswordResetHandler(req, res, deps)
    expect(deps.users.updatePassword).toHaveBeenCalledOnce()
    expect(deps.resetTokens.consume).toHaveBeenCalledWith('r1')
    expect(res.status).toHaveBeenCalledWith(200)
  })
})
